#include <bits/stdc++.h>
using namespace std;
int q[10001],l,r;
void push(int y){
    q[r]=y;
    r++;
}
void pop(){
    if(l==r){
        cout<<"ERR_CANNOT_POP"<<endl;
    }
    else{
        l++;
    }
}
void query(){
    if(l==r){
        cout<<"ERR_CANNOT_QUERY";
    }
    else {
        cout<<q[l];
    }
    cout<<endl;
}
void size(){
    cout<<r-l<<endl;
}
int main(){
    int n,x,y;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>x;
        if(x==1){
            cin>>y;
            push(y);
        }
        else if(x==2){
            pop();
        }
        else if(x==3){
            query();
        }
        else if(x==4){
            size();
        }
    }
}
